INSERT INTO "PUBLIC"."INCIDENT_REPORT" VALUES
(1, 'Servers encrypted by unknown payload deployed via an unpatched VPN vulnerability. Estimated 48-hour downtime.', 250000.00, 'Ransomware', TIMESTAMP '2026-03-05 14:18:50.886525', 'REPORTED', 2, 1),
(2, 'Patient medical records (2,500) exposed via unsecured API endpoint. Misconfiguration deployed March 1, detected March 3.', 500000.00, 'Data Breach', TIMESTAMP '2026-02-08 14:18:51.375253', 'REPORTED', 3, 2),
(3, 'Staff member clicked malicious link from spoofed admin email, exposing VPN credentials used to access patient scheduling system.', 180000.00, 'Phishing Attack', TIMESTAMP '2026-03-05 14:18:51.38255', 'UNDER_INVESTIGATION', 3, 2),
(4, 'CEO impersonation phishing led to unauthorized wire transfer of Rs.8,00,000 to a fraudulent account. Detected within 6 hours, bank freeze requested.', 800000.00, 'Phishing Attack', TIMESTAMP '2026-03-02 14:18:51.428315', 'UNDER_INVESTIGATION', 4, 3),
(33, 'Code Ddos Attack', 200000.00, 'DDoS', TIMESTAMP '2026-03-11 01:03:45.897372', 'REPORTED', 2, 33),
(65, U&'An internal employee with authorized access attempted to download sensitive company data from the internal database without proper authorization. The activity was detected through unusual access patterns and large data transfer attempts during non-working hours.\000aThe affected systems include the internal customer records database and the document management server. Immediate action was taken by the IT security team to revoke the employee''s access and isolate the affected systems.A security investigation is currently ongoing to determine the extent of the data exposure. Preliminary analysis indicates that a portion of confidential client information may have been accessed. Further forensic analysis and system audits are being conducted to assess the full impact.', 5000000.00, 'Insider Threat', TIMESTAMP '2026-03-11 11:57:54.799796', 'REPORTED', 2, 97),
(66, 'An internal employee with authorized access attempted to download sensitive company data from the internal database without proper authorization. The activity was detected through unusual access patterns and large data transfer attempts during non-working hours.', 20000000.00, 'Data Breach', TIMESTAMP '2026-03-11 12:02:39.41464', 'REPORTED', 2, 97),
(111, 'Cyber threat i.e:Data and important secure files got leaked ', 200000.00, 'Phishing', TIMESTAMP '2026-03-13 06:12:09.375696', 'REPORTED', 2, 97),
(112, 'Codedefense', 2000000.00, 'Ransomware', TIMESTAMP '2026-03-13 12:04:28.000672', 'REPORTED', 2, 33); 
