CREATE CACHED TABLE "PUBLIC"."CLAIM"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 120) NOT NULL,
    "BANK_ACCOUNT_NUMBER" CHARACTER VARYING(255),
    "BANK_IFSC_CODE" CHARACTER VARYING(255),
    "CLAIM_AMOUNT" NUMERIC(38, 2),
    "CLAIM_DESCRIPTION" CHARACTER VARYING(2000),
    "FILED_AT" TIMESTAMP(6),
    "INVESTIGATION_NOTES" CHARACTER VARYING(2000),
    "POLICE_REPORT_FILED" BOOLEAN,
    "POLICE_REPORT_NUMBER" CHARACTER VARYING(255),
    "REJECTION_REASON" CHARACTER VARYING(255),
    "REVIEWED_AT" TIMESTAMP(6),
    "SETTLEMENT_AMOUNT" NUMERIC(38, 2),
    "STATUS" ENUM('APPROVED', 'PENDING', 'REJECTED', 'SETTLED', 'UNDER_INVESTIGATION'),
    "ASSIGNED_OFFICER_USER_ID" BIGINT,
    "CUSTOMER_USER_ID" BIGINT,
    "INCIDENT_ID" BIGINT,
    "REVIEWED_BY_USER_ID" BIGINT
); 
